  "url": "http://hl7.org/fhir/uv/omop/StructureMap/PersonMap",
  "version": "1.0.0-ballot",
  "name": "PersonMap",
  "title": "Mapping Patient resource to Person OMOP Domain",
  "status": "draft",
  "date": "2025-07-29T17:40:15+00:00",
  "publisher": "HL7 International / Biomedical Research and Regulation",
  "contact": [
    {
      "name": "HL7 International / Biomedical Research and Regulation",
      "telecom": [
        {
          "system": "url",
          "value": "http://www.hl7.org/Special/committees/rcrim"
        }
      ]
    }
  ],
  "description": "This mapping maps FHIR Patient instances to OMOP Person Table objects.",
  "jurisdiction": [
    {
      "coding": [
        {
          "system": "http://unstats.un.org/unsd/methods/m49/m49.htm",
          "code": "001",
          "display": "World"
        }
      ]
    }
  ],
  "structure": [
    {
      "url": "http://hl7.org/fhir/StructureDefinition/Patient",
      "mode": "source",
      "alias": "Patient"
    },
    {
      "url": "http://hl7.org/fhir/uv/omop/StructureDefinition/Person",
      "mode": "target",
      "alias": "PersonTable"
    }
  ],
  "group": [
    {
      "name": "Person",
      "input": [
        {
          "name": "src",
          "type": "Patient",
          "mode": "source"
        },
        {
          "name": "tgt",
          "type": "PersonTable",
          "mode": "target"
        }
      ],
      "rule": [
        {
          "name": "person_id",
          "source": [
            {
              "context": "src",
              "element": "id",
              "variable": "patientId"
            }
          ],
          "target": [
            {
              "context": "tgt",
              "element": "person_id",
              "transform": "copy",
              "parameter": [
                {
                  "valueId": "patientId"
                }
              ]
            },
            {
              "context": "tgt",
              "element": "person_source_value",
              "transform": "copy",
              "parameter": [
                {
                  "valueId": "patientId"
                }
              ]
            }
          ]
        },
        {
          "name": "gender",
          "source": [
            {
              "context": "src",
              "element": "gender",
              "variable": "gender"
            }
          ],
          "target": [
            {
              "context": "tgt",
              "element": "gender_source_value",
              "transform": "copy",
              "parameter": [
                {
                  "valueId": "gender"
                }
              ]
            }
          ],
          "rule": [
            {
              "name": "setMaleConceptId",
              "source": [
                {
                  "context": "src",
                  "element": "gender",
                  "variable": "g",
                  "condition": "gender = 'male' or gender = 'M'"
                }
              ],
              "target": [
                {
                  "context": "tgt",
                  "element": "gender_concept_id",
                  "transform": "copy",
                  "parameter": [
                    {
                      "valueInteger": 8507
                    }
                  ]
                }
              ]
            },
            {
              "name": "setFemaleConceptId",
              "source": [
                {
                  "context": "src",
                  "element": "gender",
                  "variable": "g",
                  "condition": "gender = 'female' or gender = 'F'"
                }
              ],
              "target": [
                {
                  "context": "tgt",
                  "element": "gender_concept_id",
                  "transform": "copy",
                  "parameter": [
                    {
                      "valueInteger": 8532
                    }
                  ]
                }
              ]
            }
          ],
          "documentation": "Map FHIR gender to OMOP gender_concept_id: male/M -> 8507, female/F -> 8532"
        },
        {
          "name": "birthDate",
          "source": [
            {
              "context": "src",
              "element": "birthDate",
              "variable": "bdSrc"
            }
          ],
          "target": [
            {
              "context": "tgt",
              "element": "birth_datetime",
              "transform": "copy",
              "parameter": [
                {
                  "valueId": "bdSrc"
                }
              ]
            },
            {
              "context": "tgt",
              "element": "year_of_birth",
              "transform": "evaluate",
              "parameter": [
                {
                  "valueId": "src"
                },
                {
                  "valueString": "birthDate.substring(0,4)"
                }
              ]
            },
            {
              "context": "tgt",
              "element": "month_of_birth",
              "transform": "evaluate",
              "parameter": [
                {
                  "valueId": "src"
                },
                {
                  "valueString": "birthDate.substring(5,2)"
                }
              ]
            },
            {
              "context": "tgt",
              "element": "day_of_birth",
              "transform": "evaluate",
              "parameter": [
                {
                  "valueId": "src"
                },
                {
                  "valueString": "birthDate.substring(8,2)"
                }
              ]
            }
          ]
        },
        {
          "name": "raceConcept",
          "source": [
            {
              "context": "src",
              "element": "extension.where(url = 'http://hl7.org/fhir/us/core/StructureDefinition/us-core-race').extension.valueCoding.display",
              "variable": "race"
            }
          ],
          "target": [
            {
              "context": "tgt",
              "element": "race_concept_id",
              "transform": "copy",
              "parameter": [
                {
                  "valueId": "8527"
                }
              ]
            }
          ]
        },
        {
          "name": "ethnicity_concept_id",
          "documentation": "Map FHIR US Core ethnicity extension to OMOP person.ethnicity_concept_id",
          "source": [
            {
              "context": "src",
              "element": "extension.where(url = 'http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity').extension.where(url = 'ombCategory').valueCoding.code",
              "variable": "ethnicityCode"
            }
          ],
          "target": [
            {
              "context": "tgt",
              "element": "ethnicity_concept_id",
              "transform": "copy",
              "parameter": [
                {
                  "valueId": "8527"
                }
              ]
            }
          ]
        }
      ]
    }
  ]
}
